// ============================================================
// NODE: Build Smartlead Payload
// Assembles the lead payload with custom fields for each
// prospect, including creative ideas and signal data.
// ============================================================

const p = $input.item.json;
const ideas = p.creative_ideas || {};

// Parse name into first/last
const nameParts = (p.contact_name || '').trim().split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

// Build signal summary for email template variable
const signals = p.signals || {};
const activeSignals = Object.entries(signals)
  .filter(([key, val]) => val && val.detected)
  .map(([key]) => key.replace(/_/g, ' '))
  .join(', ');

return {
  json: {
    prospect_id: p.id,
    score: p.score || 'must_have',
    lead_payload: {
      email: p.contact_email,
      first_name: firstName,
      last_name: lastName,
      company_name: p.company_name,
      custom_fields: {
        creative_idea_1: ideas.idea_1 || '',
        creative_idea_2: ideas.idea_2 || '',
        creative_idea_3: ideas.idea_3 || '',
        one_liner: ideas.one_liner || '',
        lead_pillar: p.lead_pillar || 'C',
        score: p.score || 'must_have',
        signal_summary: activeSignals || 'No signals detected',
        employee_count: String(p.employee_count || ''),
        industry: p.industry || '',
        funding_stage: p.funding_stage || ''
      }
    }
  }
};

// ============================================================
// NODE: Route by Score
// Replaces Switch node for maximum compatibility.
// Output 0 = Golden, Output 1 = Strong, Output 2 = Must-Have
// ============================================================

const item = $input.item;
const score = (item.json.score || 'must_have').toLowerCase();

if (score === 'golden') {
  return [item, [], []];
} else if (score === 'strong') {
  return [[], item, []];
} else {
  return [[], [], item];
}

// ============================================================
// NODE: Parse Smartlead Response & Prepare Update
// Extracts the campaign_id and status from Smartlead's response,
// then prepares the Supabase update payload.
// ============================================================

const input = $input.item.json;

// Smartlead API returns different structures — handle gracefully
const smartleadResponse = input;
const prospectId = $('Build Smartlead Payload').item.json.prospect_id;
const score = $('Build Smartlead Payload').item.json.score;

let campaignId = '';
let pushStatus = 'unknown';

if (smartleadResponse.ok || smartleadResponse.status === 'success' || smartleadResponse.id) {
  pushStatus = 'sent';
  campaignId = smartleadResponse.campaign_id || smartleadResponse.id || '';
} else if (smartleadResponse.error || smartleadResponse.message) {
  pushStatus = 'failed';
  campaignId = '';
}

return {
  json: {
    prospect_id: prospectId,
    smartlead_campaign_id: String(campaignId),
    sent_at: pushStatus === 'sent' ? new Date().toISOString() : null,
    push_status: pushStatus,
    push_error: pushStatus === 'failed' ? (smartleadResponse.error || smartleadResponse.message || 'Unknown error') : null
  }
};

// ============================================================
// NODE: Push Summary
// Aggregates push results for monitoring/logging.
// ============================================================

const items = $('Parse Smartlead Response').all();
const sent = items.filter(i => i.json.push_status === 'sent').length;
const failed = items.filter(i => i.json.push_status === 'failed').length;

const byScore = {};
for (const item of items) {
  const score = $('Build Smartlead Payload').all()
    .find(p => p.json.prospect_id === item.json.prospect_id)?.json.score || 'unknown';
  byScore[score] = (byScore[score] || 0) + 1;
}

return {
  json: {
    summary: {
      total: items.length,
      sent,
      failed,
      by_score: byScore,
      timestamp: new Date().toISOString()
    }
  }
};
